import React, { useState, useEffect } from 'react';
import MapaCalor from './components/MapaCalor';
import Dashboard from './components/Dashboard';
import RutaSegura from './components/RutaSegura';
import Login from './components/Login';
import './App.css';

function App() {
  const [usuario, setUsuario] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [vistaActiva, setVistaActiva] = useState('mapa');

  useEffect(() => {
    if (token) {
      const userData = JSON.parse(localStorage.getItem('usuario') || '{}');
      setUsuario(userData);
    }
  }, [token]);

  const handleLogin = (tokenData) => {
    setToken(tokenData.access_token);
    localStorage.setItem('token', tokenData.access_token);
    localStorage.setItem('usuario', JSON.stringify({
      es_admin: tokenData.es_admin,
      username: tokenData.username,
    }));
    setUsuario({ es_admin: tokenData.es_admin, username: tokenData.username });
  };

  const handleLogout = () => {
    setToken(null);
    setUsuario(null);
    localStorage.removeItem('token');
    localStorage.removeItem('usuario');
  };

  if (!token) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="app">
      <header className="header">
        <div className="header-content">
          <div className="header-left">
            <div className="app-logo">🚦</div>
            <div className="app-title">
              <h1>Accidentalidad Cartagena</h1>
              <span>Sistema de análisis y prevención</span>
            </div>
          </div>
          <div className="header-actions">
            <div className="user-badge">
              <div className="user-avatar">
                {usuario?.username ? usuario.username[0].toUpperCase() : '?'}
              </div>
              <div className="user-info-text">
                <span className="user-name">{usuario?.username || 'Usuario'}</span>
                <span className="user-role">{usuario?.es_admin ? 'Administrador' : 'Usuario'}</span>
              </div>
            </div>
            <button onClick={handleLogout} className="btn-logout">
              Cerrar Sesión
            </button>
          </div>
        </div>
      </header>

      <nav className="nav">
        <button
          className={vistaActiva === 'mapa' ? 'active' : ''}
          onClick={() => setVistaActiva('mapa')}
        >
          🗺️ Mapa de Calor
        </button>
        {usuario?.es_admin && (
          <button
            className={vistaActiva === 'dashboard' ? 'active' : ''}
            onClick={() => setVistaActiva('dashboard')}
          >
            📊 Dashboard
          </button>
        )}
        <button
          className={vistaActiva === 'ruta' ? 'active' : ''}
          onClick={() => setVistaActiva('ruta')}
        >
          🛣️ Ruta Segura
        </button>
      </nav>

      <main className="main-content">
        {vistaActiva === 'mapa' && <MapaCalor token={token} />}
        {vistaActiva === 'dashboard' && usuario?.es_admin && (
          <Dashboard token={token} />
        )}
        {vistaActiva === 'ruta' && <RutaSegura token={token} />}
      </main>
    </div>
  );
}

export default App;
